import sys
sys.setrecursionlimit(10 ** 6)

def bfs(start, removed, graph, n):
    visited = [False] * (n + 1)
    q = deque([start])
    visited[start] = True
    count = 1
    while q:
        u = q.popleft()
        for v in graph[u]:
            if v == removed:
                continue
            if not visited[v]:
                visited[v] = True
                count += 1
                q.append(v)
    return count

